import{_ as t,c as a,o,a1 as d}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"鉴权失败: 401 错误排查 | Antigravity-Manager","description":"学习 Antigravity Tools 代理的鉴权机制，排查 401 错误。按 auth_mode、api_key、Header 顺序定位问题，了解 auto 模式规则与 /healthz 豁免，避免 Header 优先级误判。","frontmatter":{"title":"鉴权失败: 401 错误排查 | Antigravity-Manager","sidebarTitle":"3 分钟搞定 401","subtitle":"401/鉴权失败：先看 auth_mode，再看 Header","description":"学习 Antigravity Tools 代理的鉴权机制，排查 401 错误。按 auth_mode、api_key、Header 顺序定位问题，了解 auto 模式规则与 /healthz 豁免，避免 Header 优先级误判。","tags":["FAQ","鉴权","401","API Key"],"prerequisite":["start-proxy-and-first-client"],"order":2},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/faq/auth-401/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"}'),r={name:"zh/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"};function i(s,e,l,c,h,n){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="_401-鉴权失败-先看-auth-mode-再看-header" tabindex="-1">401/鉴权失败：先看 auth_mode，再看 Header <a class="header-anchor" href="#_401-鉴权失败-先看-auth-mode-再看-header" aria-label="Permalink to &quot;401/鉴权失败：先看 auth_mode，再看 Header&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>3 分钟内判断 401 是不是被 Antigravity Tools 的鉴权中间件拦下</li><li>弄清 <code>proxy.auth_mode</code> 四种模式（尤其是 <code>auto</code>）在你当前配置下的“实际生效值”</li><li>用正确的 API Key Header（以及避免 Header 优先级坑）让请求通过</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>客户端调用本地反代时收到 <code>401 Unauthorized</code> 错误：</p><ul><li>Python/OpenAI SDK：抛出 <code>AuthenticationError</code></li><li>curl：返回 <code>HTTP/1.1 401 Unauthorized</code></li><li>HTTP 客户端：响应状态码 401</li></ul><h2 id="什么是-401-鉴权失败" tabindex="-1">什么是 401/鉴权失败？ <a class="header-anchor" href="#什么是-401-鉴权失败" aria-label="Permalink to &quot;什么是 401/鉴权失败？&quot;">​</a></h2><p><strong>401 Unauthorized</strong> 在 Antigravity Tools 里最常见的含义是：代理启用了鉴权（由 <code>proxy.auth_mode</code> 决定），但请求没有带对 API Key，或带了一个优先级更高但不匹配的 Header，于是 <code>auth_middleware()</code> 直接返回 401。</p><div class="info custom-block"><p class="custom-block-title">先确认是不是“代理在拦”</p><p>上游平台也可能返回 401，但这篇 FAQ 只处理“代理鉴权导致的 401”。你可以先用下面的 <code>/healthz</code> 快速分辨。</p></div><h2 id="快速排查-按这个顺序做" tabindex="-1">快速排查（按这个顺序做） <a class="header-anchor" href="#快速排查-按这个顺序做" aria-label="Permalink to &quot;快速排查（按这个顺序做）&quot;">​</a></h2><h3 id="第-1-步-用-healthz-判断-鉴权是否在拦你" tabindex="-1">第 1 步：用 <code>/healthz</code> 判断“鉴权是否在拦你” <a class="header-anchor" href="#第-1-步-用-healthz-判断-鉴权是否在拦你" aria-label="Permalink to &quot;第 1 步：用 `/healthz` 判断“鉴权是否在拦你”&quot;">​</a></h3><p><strong>为什么</strong><code>all_except_health</code> 会放行 <code>/healthz</code>，但会拦住其他路由；这能帮你快速定位 401 是否来自代理鉴权层。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 不带任何鉴权 Header</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/healthz</span></span></code></pre></div><p><strong>你应该看到</strong></p><ul><li><code>auth_mode=all_except_health</code>（或 <code>auto</code> 且 <code>allow_lan_access=true</code>）时：通常会返回 <code>200</code></li><li><code>auth_mode=strict</code> 时：会返回 <code>401</code></li></ul><div class="tip custom-block"><p class="custom-block-title"><code>/healthz</code> 在路由层是 GET</p><p>代理在路由里注册的是 <code>GET /healthz</code>（见 <code>src-tauri/src/proxy/server.rs</code>）。</p></div><hr><h3 id="第-2-步-确认-auth-mode-的-实际生效值-尤其是-auto" tabindex="-1">第 2 步：确认 <code>auth_mode</code> 的“实际生效值”（尤其是 <code>auto</code>） <a class="header-anchor" href="#第-2-步-确认-auth-mode-的-实际生效值-尤其是-auto" aria-label="Permalink to &quot;第 2 步：确认 `auth_mode` 的“实际生效值”（尤其是 `auto`）&quot;">​</a></h3><p><strong>为什么</strong><code>auto</code> 不是一个“独立策略”，它会根据 <code>allow_lan_access</code> 计算出真正要执行的模式。</p><table tabindex="0"><thead><tr><th><code>proxy.auth_mode</code></th><th>额外条件</th><th>实际生效值（effective mode）</th></tr></thead><tbody><tr><td><code>off</code></td><td>-</td><td><code>off</code></td></tr><tr><td><code>strict</code></td><td>-</td><td><code>strict</code></td></tr><tr><td><code>all_except_health</code></td><td>-</td><td><code>all_except_health</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=false</code></td><td><code>off</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=true</code></td><td><code>all_except_health</code></td></tr></tbody></table><p><strong>你可以在 GUI 的 API Proxy 页面检查</strong>：<code>Allow LAN Access</code> 和 <code>Auth Mode</code>。</p><hr><h3 id="第-3-步-确认-api-key-不是空的-并且你用的是同一个值" tabindex="-1">第 3 步：确认 <code>api_key</code> 不是空的，并且你用的是同一个值 <a class="header-anchor" href="#第-3-步-确认-api-key-不是空的-并且你用的是同一个值" aria-label="Permalink to &quot;第 3 步：确认 `api_key` 不是空的，并且你用的是同一个值&quot;">​</a></h3><p><strong>为什么</strong> 鉴权开启时，如果 <code>proxy.api_key</code> 为空，<code>auth_middleware()</code> 会直接拒绝全部请求并打错误日志。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy auth is enabled but api_key is empty; denying request</span></span></code></pre></div><p><strong>你应该看到</strong></p><ul><li>API Proxy 页面里能看到一个以 <code>sk-</code> 开头的 key（默认值在 <code>ProxyConfig::default()</code> 会自动生成）</li><li>点击“Regenerate/编辑”保存后，外部请求立刻按新 key 校验（无需重启）</li></ul><hr><h3 id="第-4-步-用最简单的-header-试一次-先别用复杂-sdk" tabindex="-1">第 4 步：用最简单的 Header 试一次（先别用复杂 SDK） <a class="header-anchor" href="#第-4-步-用最简单的-header-试一次-先别用复杂-sdk" aria-label="Permalink to &quot;第 4 步：用最简单的 Header 试一次（先别用复杂 SDK）&quot;">​</a></h3><p><strong>为什么</strong> 中间件会优先读取 <code>Authorization</code>，再读 <code>x-api-key</code>，最后读 <code>x-goog-api-key</code>。如果你同时发了多个 Header，前面的那个错了，后面的那个就算对也不会被用上。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 推荐写法：Authorization + Bearer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><p><strong>你应该看到</strong>：<code>HTTP/1.1 200 OK</code>（或至少不再是 401）</p><div class="info custom-block"><p class="custom-block-title">代理对 Authorization 的兼容细节</p><p><code>auth_middleware()</code> 会把 <code>Authorization</code> 的值按 <code>Bearer </code> 前缀做一次剥离；如果没有 <code>Bearer </code> 前缀，也会把整个值当成 key 去比对。文档仍推荐 <code>Authorization: Bearer &lt;key&gt;</code>（更符合通用 SDK 约定）。</p></div><p><strong>如果你必须用 <code>x-api-key</code></strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><hr><h2 id="常见坑-都是源码里真实会发生的" tabindex="-1">常见坑（都是源码里真实会发生的） <a class="header-anchor" href="#常见坑-都是源码里真实会发生的" aria-label="Permalink to &quot;常见坑（都是源码里真实会发生的）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>真实原因</th><th>你该怎么改</th></tr></thead><tbody><tr><td><code>auth_mode=auto</code>，但本机调用仍然 401</td><td><code>allow_lan_access=true</code> 导致 <code>auto</code> 生效为 <code>all_except_health</code></td><td>关闭 <code>allow_lan_access</code>，或让客户端带上 key</td></tr><tr><td>你觉得“我明明带了 x-api-key”，但仍 401</td><td>同时带了一个不匹配的 <code>Authorization</code>，中间件优先用它</td><td>删掉多余 Header，只保留一个你确定正确的</td></tr><tr><td><code>Authorization: Bearer&lt;key&gt;</code> 仍 401</td><td><code>Bearer</code> 后少了空格，无法按 <code>Bearer </code> 前缀剥离</td><td>改成 <code>Authorization: Bearer &lt;key&gt;</code></td></tr><tr><td>所有请求都 401，日志出现 <code>api_key is empty</code></td><td><code>proxy.api_key</code> 为空</td><td>在 GUI 里重新生成/设置一个非空 key</td></tr></tbody></table><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>先用 <code>/healthz</code> 定位 401 是否来自代理鉴权层</li><li>再确认 <code>auth_mode</code>（尤其是 <code>auto</code> 的 effective mode）</li><li>最后只带一个确定正确的 Header 去验证（避免 Header 优先级坑）</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../429-rotation/">429/容量错误：账号轮换的正确预期与模型容量耗尽的误区</a></strong>。</p><p>你会学到：</p><ul><li>429 到底是“配额不足”还是“上游限流”</li><li>账号轮换的正确预期（什么时候会自动切、什么时候不会）</li><li>用配置把 429 的概率压下去</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>ProxyAuthMode 枚举</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L5-L18" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>5-18</td></tr><tr><td>ProxyConfig: allow_lan_access/auth_mode/api_key 与默认值</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-258</td></tr><tr><td>auto 模式解析（effective_auth_mode）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/security.rs#L1-L30" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/security.rs</code></a></td><td>1-30</td></tr><tr><td>鉴权中间件（Header 提取与优先级、/healthz 豁免、OPTIONS 放行）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/auth.rs#L14-L77" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/auth.rs</code></a></td><td>14-77</td></tr><tr><td>/healthz 路由注册与中间件顺序</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L170-L193" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>170-193</td></tr><tr><td>鉴权文档（模式与客户端约定）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy/auth.md#L1-L45" target="_blank" rel="noreferrer"><code>docs/proxy/auth.md</code></a></td><td>1-45</td></tr></tbody></table><p><strong>关键枚举</strong>：</p><ul><li><code>ProxyAuthMode::{Off, Strict, AllExceptHealth, Auto}</code>：鉴权模式</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>ProxySecurityConfig::effective_auth_mode()</code>：把 <code>auto</code> 解析成真实策略</li><li><code>auth_middleware()</code>：执行鉴权（含 Header 提取顺序与 /healthz 豁免）</li></ul></details>',45)])])}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
